INSERT INTO `cers_holland_result` VALUES (1,1,1,9,6,9,11,9,6,'SRA','你的霍兰德代码为 SRA。\n\n【社会型(Social)】你善于与人交往，乐于助人，具有较强的沟通能力和同理心。\n【现实型(Realistic)】你喜欢动手操作，倾向于与物体、机器、工具打交道，具有较强的实践能力。\n【艺术型(Artistic)】你富有创造力和想象力，喜欢通过艺术形式表达自我，追求自由和个性。\n','[{\"majors\":[{\"universityId\":34,\"majorId\":253,\"minScore2024\":532,\"majorName\":\"教育学类\"},{\"universityId\":57,\"majorId\":543,\"minScore2024\":577,\"majorName\":\"教育学\"},{\"universityId\":3,\"majorId\":11,\"minScore2024\":589,\"majorName\":\"教育学\"},{\"universityId\":11,\"majorId\":86,\"minScore2024\":639,\"majorName\":\"教育学\"},{\"universityId\":42,\"majorId\":324,\"minScore2024\":448,\"majorName\":\"学前教育\"}],\"description\":\"适合有耐心和热爱教育事业的人\",\"hollandCode\":\"S\",\"direction\":\"教育\"},{\"majors\":[{\"universityId\":342,\"majorId\":1457,\"minScore2024\":504,\"majorName\":\"应用心理学\"},{\"universityId\":62,\"majorId\":605,\"minScore2024\":527,\"majorName\":\"应用心理学\"},{\"universityId\":53,\"majorId\":498,\"minScore2024\":530,\"majorName\":\"应用心理学\"},{\"universityId\":53,\"majorId\":497,\"minScore2024\":543,\"majorName\":\"应用心理学\"},{\"universityId\":35,\"majorId\":265,\"minScore2024\":549,\"majorName\":\"应用心理学\"}],\"description\":\"适合善于理解他人、乐于助人的人\",\"hollandCode\":\"S\",\"direction\":\"心理健康\"},{\"majors\":[{\"universityId\":62,\"majorId\":607,\"minScore2024\":451,\"majorName\":\"护理学\"},{\"universityId\":58,\"majorId\":561,\"minScore2024\":463,\"majorName\":\"护理学\"},{\"universityId\":69,\"majorId\":736,\"minScore2024\":477,\"majorName\":\"护理学\"},{\"universityId\":261,\"majorId\":1243,\"minScore2024\":502,\"majorName\":\"护理学\"},{\"universityId\":347,\"majorId\":1462,\"minScore2024\":502,\"majorName\":\"护理学\"}],\"description\":\"适合细心、有爱心的人\",\"hollandCode\":\"S\",\"direction\":\"医疗护理\"},{\"majors\":[{\"universityId\":70,\"majorId\":740,\"minScore2024\":501,\"majorName\":\"法学\"},{\"universityId\":136,\"majorId\":937,\"minScore2024\":506,\"majorName\":\"法学\"},{\"universityId\":230,\"majorId\":1166,\"minScore2024\":521,\"majorName\":\"法学\"},{\