DROP TABLE IF EXISTS `cers_major_detail`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `cers_major_detail` (
  `detail_id` bigint NOT NULL AUTO_INCREMENT COMMENT '明细ID',
  `major_id` bigint NOT NULL COMMENT '专业组ID，外键关联到cers_major表',
  `specific_major_name` varchar(100) NOT NULL COMMENT '具体专业名称（如：软件工程、临床医学）',
  `plan_count` int DEFAULT NULL COMMENT '招生计划人数',
  `tuition_fee` int DEFAULT NULL COMMENT '学费（元/年）',
  `study_years` varchar(20) DEFAULT NULL COMMENT '学制（如：4年、5年）',
  `requirements` text COMMENT '特殊要求及备注',
  PRIMARY KEY (`detail_id`),
  KEY `idx_major_id` (`major_id`)
) ENGINE=InnoDB AUTO_INCREMENT=31704 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='专业组下辖具体专业明细表';
/*!40101 SET character_set_client = @saved_cs_client */;

