INSERT INTO `cers_major_detail` VALUES (1,16504,'文科试验班类(国关)',2,5000,'四年','包含专业:社会学类。'),(2,16504,'人文科学试验班',1,5000,'四年','包含专业:艺术史论。'),(3,16504,'哲学类',2,5000,'四年','包含专业:哲学、宗教学、哲学(科技哲学与逻辑学方向)。'),(4,16504,'经济学类',1,5000,'四年','包含专业:经济学、金融学、国际经济与贸易、财政学。'),(5,16504,'法学',3,5000,'四年',NULL),(6,16504,'社会学类',2,5000,'四年','包含专业:社会学、社会工作。'),(7,16504,'中国语言文学类',2,5000,'四年','包含专业:汉语言文学、汉语言、古典文献学、应用语言学。'),(8,16504,'新闻传播学类',2,5000,'四年','包含专业:新闻学、广播电视学、广告学。'),(9,16504,'历史学类',1,5000,'四年','包含专业:历史学(中国史)、世界史、外国语言与外国历史。'),(10,16504,'考古学',2,5000,'四年',NULL),(11,16504,'城乡规划',1,5000,'四年',NULL),(12,16504,'工商管理类',1,5000,'四年','包含专业:金融学、金融学(金融经济学)、会计学、市场营销。'),(13,16504,'公共管理类',1,5000,'四年','包含专业:城市管理、行政管理。'),(14,16504,'图书馆学',2,5000,'四年',NULL),(15,16504,'英语',2,5000,'四年',NULL),(16,16504,'文科试验班类(元培)',1,5300,'四年','包含专业:中国语言文学类、考古学、历史学类、哲学类、社会学类、法学、新闻传播学类、经济学类、工商管理类、公共管理类。'),(17,16505,'文科试验班类(国关)',1,5000,'四年','包含专业:社会学类。'),(18,16505,'人文科学试验班',1,5000,'四年','包含专业:艺术史论。'),(19,16505,'社会学类',1,5000,'四年','包含专业:社会学、社会工作。'),(20,16505,'公共管理类',1,5000,'四年','包含专业:城市管理、行政管理。'),(21,16505,'图书馆学',1,5000,'四年',NULL),(22,16506,'文科试验班类(外文实验班)',1,5000,'四年','包含专业:英语。'),(23,16506,'文科试验班类(经济、金融与管理)',1,5000,'四年','包含专业:经济与金融(国际班)。'),(24,16506,'文科试验班类(至善书院)',1,5000,'四年','包含专业:经济学、社会学。'),(25,16506,'法学类',1,5000,'四年','包含专业:法学(含国际班)。'),(26,16507,'文科试验班类(外文实验班)',1,5000,'四年','包含专业:英语。'),(27,16507,'法学类',1,5000,'四年','包含专业:法学(含国际班)。'),(28,16508,'法学',3,5000,'四年','含涉外法治战略人才班；国际交流：含哈佛大学、鲁汶大学、新加坡国立大学等院际交换项目，“亚洲校园+”项目（中日韩三国政府奖学金支持）、中欧欧洲法国际组织后备人才培养项目（国家留基委资助）等。'),(29,16509,'中国古典学(拔尖人才班)',2,5000,'四年',NULL),(30,16509,'工商管理类(数智化方向)',6,5000,'四年','无时点专业选择。特色培养项目：中意美三学位管理学战略人才班；培养专业含贸易经济(国际商务方向)、会计学(智能会计方向)；国际交流：含新加坡南洋理工大学、西班牙ESADE商学院、荷兰阿姆斯特丹大学、比利时KU Leuven等校免学费交流项目。 包含专业:工商管理、财务管理、会计学、市场营销、贸易经济。'),(31,16509,'新闻传播学类(新媒体与数据管理创新人才班)',1,5000,'四年','新闻学院和信息资源管理学院共同培养，毕业获文学、管理学双主学士学位 包含专业:传播学。'),(32,16509,'经济学类(新时代经济学拔尖人才班)',2,5000,'四年','包含专业:经济学。'),(33,16509,'人文科学试验班(社会科学基础理论拔尖人才班)',1,5000,'四年','历史学院、社会学院和经济学院共同培养，毕业获历史学、法学或经济学（任选其一）双主学士学位 包含专业:历史学。'),(34,16509,'人力资源管理(经管交叉)',3,5000,'四年','内设人力资源管理、劳动经济、劳动与社会保障、劳动关系4个专业，无时点专业选择，毕业时可获经济学或管理学学位；含“数字化人才管理”荣誉辅修项目。'),(35,16509,'公共管理类(行政、土地、城市)',7,5000,'四年','大类中专业任选。国家一流本科专业，国际交流：美国华盛顿大学、英国剑桥大学、德国慕尼黑工业大学、荷兰格罗宁根大学、日本一桥大学等学生交换项目。 包含专业:行政管理、城市管理、土地资源管理。'),(36,16509,'新闻传播学类',3,5000,'四年','无时点专业选择；培养方向涵盖智能传播、全媒体新闻生产、国际传播、视听传播等国家前沿战略发展领域；特色培养项目：国际新闻传播战略人才班；国际交流：与多所世界知名大学新闻院系建立联合培养关系，境外交流奖学金资助全员覆盖。 包含专业:新闻学、广播电视学、广告学、传播学、国际新闻与传播。'),(37,16509,'社会学类',2,5000,'四年','无时点专业选择；国际交流：含芝加哥大学、加州大学、密歇根大学等名校学生交换项目（专项奖学金支持）；含田野课堂项目，“航笙优才培养项目”。 包含专业:社会学、社会工作。'),(38,16509,'经济学类',6,5000,'四年','无时点专业选择：学院内专业任选，毕业时认定专业。国际交流：美国伊利诺伊大学香槟分校、威斯康星大学麦迪逊分校、英国曼彻斯特大学、日本九州大学等名校联合培养项目，英国牛津大学、德国波鸿鲁尔大学等夏/冬令营项目。 包含专业:经济学、国民经济管理、能源经济、国际经济与贸易。'),(39,16509,'资源与环境经济学',1,5000,'四年','全面的科研训练和社会实训，暑期”行走美丽中国”暑期实践教学涵盖国家公园等自然保护地，培养绿色低碳发展前沿的生态文明建设复合型高端人才'),(40,16509,'信息资源管理',1,5000,'四年','内设信息资源管理、档案学、大数据管理与应用3个专业，无时点专业选择；全学程导师制度；本科生国际交流机会全覆盖。'),(41,16509,'人文科学试验班',3,5000,'四年','大类中专业任选。国际学位项目：根特大学、夏威夷大学培养项目，加拿大西安大略大学哲学系“1+1+1”项目。国际交流项目：约翰霍普金斯大学、牛津大学赫特福德学院、香港科技大学等学生交换项目，日本东京大学互访研学项目，德国波恩大学交流项目等。 包含专业:哲学、宗教学、伦理学、汉语言文学、汉语言、历史学、世界史、考古学、中国古典学。'),(42,16509,'金融学类',6,5000,'四年','大类中专业任选。国际交流：含剑桥大学本科生访学项目、康奈尔大学暑期学校，伊利诺伊大学香槟分校、明尼苏达双城大学、威斯康辛大学麦迪逊分校、新加坡管理大学联合培养等。 包含专业:金融学、保险学。'),(43,16510,'政治学、经济学与哲学(PPE)',1,5000,'四年','教学涵盖哲学、政治学和经济学三个专业内容；国际交流：含牛津大学赫特福德学院院际学生交换项目、意大利帕多瓦大学学生交换项目；牛津大学、华威大学和曼彻斯特大学的短期访学项目。'),(44,16510,'国际政治',1,5000,'四年','内设政治学与行政学、国际政治、外交学3个专业。国际交流：含16国30余所海外名校学生交换项目（专项奖学金资助），全球治理与国际组织高端人才培养项目，伦敦大学国王学院联合培养。'),(45,16511,'工商管理类(数智化方向)',1,5000,'四年','无时点专业选择。特色培养项目：中意美三学位管理学战略人才班；培养专业含贸易经济(国际商务方向)、会计学(智能会计方向)；国际交流：含新加坡南洋理工大学、西班牙ESADE商学院、荷兰阿姆斯特丹大学、比利时KU Leuven等校免学费交流项目。 包含专业:工商管理、财务管理、会计学、市场营销、贸易经济。'),(46,16511,'农业经济管理类',2,5000,'四年','无时点专业选择：涵盖农林经济管理、农村区域发展两大国家级一流本科专业，跨学科深度培养。衔接培养：全员纳入“卓越三农”培养，综合能力全面提升；战略育人：“智农班”+新路引航项目，对接国家战略需求；全球赋能：国际化培养全覆盖，招培就链条全畅通。'),(47,16511,'应用心理学',1,5000,'四年','国家一流本科专业-双维课程：心理学核心课程体系+交叉学科课程体系；双重导师：生涯导师+学术导师；双轮实践：校内实践+校外实践；双向视野：人类心理研究的国际视野+人民心理实践的本土视野。'),(48,16511,'外国语言文学类',1,6000,'四年','各语种均有机会进入目标语言国著名高校进行交流学习 包含专业:日语、俄语、德语、法语、西班牙语。'),(49,16512,'中国共产党历史',1,5000,'四年',NULL),(50,16512,'国际政治',2,5000,'四年','内设政治学与行政学、国际政治、外交学3个专业。国际交流：含16国30余所海外名校学生交换项目（专项奖学金资助），全球治理与国际组织高端人才培养项目，伦敦大学国王学院联合培养。'),(51,16513,'人文科学试验班(励耘实验班)',2,4800,'四年','包含专业:汉语言文学、历史学、哲学。'),(52,16513,'哲学',2,4800,'四年',NULL),(53,16513,'汉语言文学',2,4800,'四年',NULL),(54,16513,'历史学类',2,4800,'四年','包含专业:历史学、考古学。'),(55,16513,'教育学类',3,4800,'四年','另含：教育技术学 包含专业:教育学、学前教育、特殊教育。'),(56,16513,'汉语言文学',2,4800,'四年','“汉语言文学（应用语言学方向）+人工智能”双学士学位复合型人才培养项目'),(57,16513,'国际经济与贸易',2,5000,'四年',NULL),(58,16513,'英语(卓师计划实验班)',2,6000,'四年',NULL),(59,16514,'政治学、经济学与哲学',2,4800,'四年',NULL),(60,16515,'传播学(网络新媒体方向)',3,4800,'四年',NULL),(61,16515,'历史学类',2,4800,'四年','包含专业:历史学、考古学。'),(62,16516,'思想政治教育',2,4800,'四年',NULL),(63,16517,'工商管理类(数智管理试验班)',2,5000,'四年','“工商管理+人工智能”双学士学位项目 包含专业:工商管理(工商、智能双学士学位)、会计学。'),(64,16517,'社会科学试验班',9,5000,'四年','包含专业:法学、社会工作(社会管理)、行政管理。'),(65,16517,'外国语言文学类',4,5000,'四年','入学后可参与英语+人工智能、日语+人工智能双学士学位选拔。 包含专业:英语、日语、德语。'),(66,16518,'工商管理(数智管理实验班)',5,5000,'四年','一年级在沙河校区，二、三、四年级将根据学校规划安排在沙河校区或西土城路校区。'),(67,16518,'法学(与中国政法大学联合学位)',2,5000,'四年',NULL),(68,16518,'网络与新媒体',2,5000,'四年',NULL),(69,16518,'英语(语言智能实验班)',5,5500,'四年',NULL),(70,16519,'社会科学试验班',6,5000,'四年','含人工智能-行政管理双学士学位项目、法学-人工智能双学士学位项目，具体包含专业详见学校招生信息报考指南专栏。 包含专业:经济学、行政管理、法学。'),(71,16520,'社会科学试验班(人文社科方向)',7,5000,'四年','包含专业:法学(含AI 双学位)、法学、法学（中国政法大学联合培养）、社会工作、英语、日语、德语、西班牙语、德语(含车辆工程双学位)、英语（含法学双学位）。'),(72,16520,'社会科学试验班(徐特立英才班之国际组织和全球治理)',3,5000,'四年','包含专业:法学、工商管理、公共事业管理。'),(73,16520,'社会科学试验班(管理与经济方向)',6,5000,'四年','包含专业:工商管理(含数字创新管理方向)、工商管理(含AI双学位)、经济学、国际经济与贸易(含数字金融、数字贸易方向)。'),(74,16521,'文科试验班类(经济管理人才试点班)',3,5000,'四年','包含专业:工商管理、会计学。'),(75,16521,'法学',3,5000,'四年',NULL),(76,16522,'新闻传播学类(卓越人才拔尖班)',2,5000,'四年','特殊培养方案，详见学校招生网站 包含专业:网络与新媒体、国际新闻与传播。'),(77,16523,'建筑类(卓越人才拔尖班)',4,5500,'五年','特殊培养方案，详见学校招生网站 包含专业:建筑学、城乡规划。'),(78,16524,'外国语言文学类(语言智能实验班)',3,5500,'四年','语言智能、英语和西班牙语双语 包含专业:英语、西班牙语。'),(79,16525,'法学(卓越实验班)',1,5000,'四年',NULL),(80,16525,'工商管理类(新文科经管法)',10,5000,'四年','包含专业:财务管理、会计学、工商管理、国际经济与贸易、行