/*!40000 ALTER TABLE `sys_notice` DISABLE KEYS */;
INSERT INTO `sys_notice` VALUES (1,'欢迎大家预约','2',_binary '<p>高考报名推荐系统开放啦，欢迎大家积极使用。</p>','0','admin','2026-02-28 22:23:43','admin','2026-02-06 11:37:36','管理员'),(2,'高考报名推荐系统维护','1',_binary '<p>系统维护中，两天后正常开放。</p>','0','admin','2026-02-28 22:23:43','admin','2026-02-06 11:37:39','管理员'),(10,'2025 年广东省高考志愿填报新政策解读','1',_binary '<p><strong>1  填报方式与确认</strong></p><p><br></p><ul><li><strong>填报方式：</strong><span style=\"color: rgba(0, 0, 0, 0.85);\">实行网上填报志愿，考生凭本人普通高考报名注册账号和密码登录广东省普通高考报名系统填报志愿。</span></li><li><strong>志愿确认：</strong><span style=\"color: rgba(0, 0, 0, 0.85);\">不设现场签名确认环节，通过高考报名时绑定的手机号码接收短信验证码或人脸比对两种方式完成网上志愿填报及确认，投档录取以考生网上最终确认的志愿为依据。</span></li></ul><p><strong>2  填报时间</strong></p><p><br></p><ul><li><strong>春季高考：</strong><span style=\"color: rgba(0, 0, 0, 0.85);\">3 月 13 日 14：00 至 17 日 12：00，考生登录系统选择春季高考 “依学考录取” 或 “3 + 证书” 考试中的一类填报志愿。</span></li><li><strong>夏季高考：</strong><span style=\"color: rgba(0, 0, 0, 0.85);\">暂未公布具体时间，可参考往年一般在高考成绩公布后几天内开始填报。</span></li></ul><p><strong>3  志愿设置</strong></p><p><br></p><ul><li><strong>春季高考：</strong></li><li><span style=\"color: rgb(0, 0, 0);\">“依学考录取”：</span><span style=\"color: rgba(0, 0, 0, 0.85);\">不分批次，分普通类、艺体类两大类别。普通类设 20 个院校专业组志愿，艺体类设 10 个院校专业组志愿，每个院校专业组包含 6 个专业志愿和 1 个是否服从专业调剂选项，普通类与艺体类不得兼报。</span></li><li><span style=\"color: rgb(0, 0, 0);\">“3 + 证书” 考试</span>：<span style=\"color: rgba(0, 0, 0, 0.85);\">分本科、高职（专科）两个批次，两个批次同时填报志愿。本科批次设 1 个院校专业组志愿，每个院校专业组设 1 个专业志愿，不设是否服从专业调剂选项；高职（专科）批次按考生类型分中职生批次、退役士兵批次、内地西藏新疆班批次，中职生批次设 35 个院校专业组志愿，退役士兵批次设 10 个院校专业组志愿，内地西藏新疆班批次设 1 个院校专业组志愿，每个院校专业组包含的专业志愿和调剂选项不同。</span></li><li><strong>夏季高考：</strong><span style=\"color: rgba(0, 0, 0, 0.85);\">普通类分本科提前批、本科批、普通高职（专科）提前批和普通高职（专科）批四个批次。本科提前批中，军校招飞 1 个志愿，军检院校公安院校 10 个志愿，师范农林小语种院校 20 个志愿，教师专项批 10 个志愿；本科批和专科批可填报 45 个院校专业组志愿，每个院校专业组设 6 个专业志愿和 1 个是否服从专业调剂选项；专科提前批可填报 5 个志愿。</span></li></ul><p><strong>4  投档办法</strong></p><p><br></p><ul><li><strong>春季高考：</strong></li><li><span style=\"color: rgb(0, 0, 0);\">“依学考录取”：</span><span style=\"color: rgba(0, 0, 0, 0.85);\">在各类别最低录取分数线上，按照平行志愿 “分数优先、遵循志愿” 原则进行投档。普通类按考生学考成绩排序检索；艺体类在考生学考成绩、专业省统考成绩双上线基础上，按合成总分排序检索。</span></li><li><span style=\"color: rgb(0, 0, 0);\">“3 + 证书” 考试</span>：<span style=\"color: rgba(0, 0, 0, 0.85);\">分本科批次和专科批次，按先本科、后专科顺序进行投档录取。本科批次将符合条件考生投档给高校，由高校按一定比例合成总分择优录取；专科中职生、退役士兵和内地西藏新疆班批次，按考生统一文化科目考试合成总分投档排位从高到低检索，由招生院校按章程录取。</span></li><li><strong>夏季高考：</strong><span style=\"color: rgba(0, 0, 0, 0.85);\">采用平行志愿模式，遵循 “分数优先、遵循志愿” 的原则。按考生总成绩从高到低依次检索考生所填报的志愿，当检索到符合投档条件的志愿时，即将考生档案投递，考生在每批次内只有一次投档机会。</span></li></ul><p><strong>5  注意事项</strong></p><p><br></p><ul><li><strong>关注选科要求：</strong><span style=\"color: rgba(0, 0, 0, 0.85);\">各高校依据专业特点设定具体的选考科目要求，考生填报志愿时需仔细核对招生计划，确保自身选科组合符合报考条件。</span></li><li><strong>重视体检结果：</strong><span style=\"color: rgba(0, 0, 0, 0.85);\">考生要按要求参加体检并上传数据，避免因身体条件受限而被退档。</span></li><li><strong>合理设置志愿梯度：</strong><span style=\"color: rgba(0, 0, 0, 0.85);\">填报志愿时要综合考虑自身成绩、院校录取分数线和招生计划等因素，合理设置志愿梯度，增大投档成功的概率。</span></li><li><strong>谨慎选择是否服从专业调剂：</strong><span style=\"color: rgba(0, 0, 0, 0.85);\">由于平行志愿只有一次投档机会，若不服从专业调剂，可能会被退档，只能参加征集志愿或下一批次录取。  </span></li></ul>','0','admin','2026-02-28 13:55:29','admin','2026-02-06 11:37:45',NULL);
